const body = $json.body ?? $json;
const from = body.From ?? body.from ?? body.WaId ?? '';
const message = body.Body ?? body.body ?? body.ButtonText ?? body.ButtonPayload ?? '';
return [{ json: { telefono: from, mensaje: message, tipo: 'text', twilioFrom: from } }];

function esc(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}
const botones = Array.isArray($json.botones) ? $json.botones : [];
let texto = $json.respuesta || 'Tuve un problema. Intenta de nuevo en un momento.';
if (botones.length) {
  texto += '\n\nResponde: ' + botones.map((b) => b.titulo).join(' / ');
}
const twiml = `<?xml version="1.0" encoding="UTF-8"?><Response><Message>${esc(texto)}</Message></Response>`;
return [{ json: { twiml } }];
